class SketchEstimatorThemeJoinAccuracyTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI THEME_GRAPH = VF.createIRI("urn:test:theme-graph");
	private static final int TOP_PO_PAIRS = 80;
	private static final int REQUIRED_JOIN_SCENARIOS = 5;
	private static final int MIN_INTERSECTION = 25;
	private static final double MAX_RELATIVE_ERROR = 0.20d;

	@Test
	void estimatorMatchesManualJoinAcrossAllThemes(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadAllThemesInSingleGraph(repository);
			SketchBasedJoinEstimator estimator = store.getBackingStore().getSketchBasedJoinEstimator();

			EvaluationStatistics statistics = store.getBackingStore().getEvaluationStatistics();
			assertTrue(awaitJoinEstimationReady(statistics),
					"LMDB evaluation statistics should expose join estimation after test-data load");

			List<JoinScenario> scenarios = selectJoinScenarios(repository);
			assertTrue(scenarios.size() >= REQUIRED_JOIN_SCENARIOS,
					() -> "Insufficient join scenarios. Found: " + scenarios.size());

			for (int i = 0; i < REQUIRED_JOIN_SCENARIOS; i++) {
				JoinScenario scenario = scenarios.get(i);
				double estimate = statistics.getCardinality(asJoinNode(scenario));

				if (estimate <= 0.0d) {
					System.out.println(
							"Estimator returned zero for scenario left=" + scenario.left + ", right=" + scenario.right
									+ ", actual=" + scenario.actualJoinCount());
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));

				}

				assertTrue(estimate > 0.0d,
						() -> "Estimator returned zero for scenario left=" + scenario.left + ", right=" + scenario.right
								+ ", actual=" + scenario.actualJoinCount());

				double relativeError = Math.abs(estimate - scenario.actualJoinCount()) / scenario.actualJoinCount();
				if (relativeError > MAX_RELATIVE_ERROR) {
					System.out.println("Scenario sizes leftSubjects=" + scenario.leftSubjects() + ", rightSubjects="
							+ scenario.rightSubjects() + ", intersection=" + scenario.actualJoinCount());
					printDirectPairCounts(repository, scenario);
				}
				if (relativeError > MAX_RELATIVE_ERROR) {
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
					statistics.getCardinality(asJoinNode(scenario));
				} else {
					System.out.println("Join estimate within 20% bound. left=" + scenario.left + ", right="
							+ scenario.right + ", estimate=" + estimate + ", actual=" + scenario.actualJoinCount()
							+ ", error=" + relativeError);
				}
				if (relativeError > MAX_RELATIVE_ERROR) {
					printScenarioDiagnostics(estimator, scenario);
				}

				assertTrue(relativeError <= MAX_RELATIVE_ERROR,
						() -> "Join estimate outside 20% bound. left=" + scenario.left + ", right="
								+ scenario.right + ", estimate=" + estimate + ", actual="
								+ scenario.actualJoinCount() + ", error=" + relativeError);
			}
		} finally {
			repository.shutDown();
		}
	}

	private static void printScenarioDiagnostics(SketchBasedJoinEstimator estimator, JoinScenario scenario) {
		String context = THEME_GRAPH.stringValue();
		String leftPredicate = scenario.left.predicate().stringValue();
		String leftObject = scenario.left.object().stringValue();
		String rightPredicate = scenario.right.predicate().stringValue();
		String rightObject = scenario.right.object().stringValue();

		double leftEstimate = estimator.estimateCount(SketchBasedJoinEstimator.Component.S, null, leftPredicate,
				leftObject, context);
		double rightEstimate = estimator.estimateCount(SketchBasedJoinEstimator.Component.S, null, rightPredicate,
				rightObject, context);
		double poLeft = estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PO, leftPredicate, leftObject);
		double pcLeft = estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PC, leftPredicate, context);
		double ocLeft = estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.OC, leftObject, context);
		double poRight = estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PO, rightPredicate, rightObject);
		double pcRight = estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PC, rightPredicate, context);
		double ocRight = estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.OC, rightObject, context);
		double pairJoinEstimate = estimator.estimateJoinOn(SketchBasedJoinEstimator.Component.S,
				SketchBasedJoinEstimator.Pair.PO, leftPredicate, leftObject, SketchBasedJoinEstimator.Pair.PO,
				rightPredicate, rightObject);

		System.out.println("Diagnostics leftEstimate=" + leftEstimate + ", rightEstimate=" + rightEstimate
				+ ", pairJoinEstimate(POxPO)=" + pairJoinEstimate);
		System.out.println("Diagnostics leftPairs po=" + poLeft + ", pc=" + pcLeft + ", oc=" + ocLeft);
		System.out.println("Diagnostics rightPairs po=" + poRight + ", pc=" + pcRight + ", oc=" + ocRight);
	}

	private static void printDirectPairCounts(SailRepository repository, JoinScenario scenario) {
		long leftStatements = 0L;
		long rightStatements = 0L;
		Set<String> leftSubjects = new HashSet<>();
		Set<String> rightSubjects = new HashSet<>();

		try (SailRepositoryConnection connection = repository.getConnection();
				CloseableIteration<? extends Statement> left = connection.getStatements(
						null, scenario.left.predicate(), scenario.left.object(), false, THEME_GRAPH);
				CloseableIteration<? extends Statement> right = connection.getStatements(
						null, scenario.right.predicate(), scenario.right.object(), false, THEME_GRAPH)) {
			while (left.hasNext()) {
				Statement st = left.next();
				leftStatements++;
				leftSubjects.add(st.getSubject().stringValue());
			}
			while (right.hasNext()) {
				Statement st = right.next();
				rightStatements++;
				rightSubjects.add(st.getSubject().stringValue());
			}
		}

		System.out.println("Direct counts leftStatements=" + leftStatements + ", leftDistinctSubjects="
				+ leftSubjects.size() + ", rightStatements=" + rightStatements + ", rightDistinctSubjects="
				+ rightSubjects.size());
	}

	private static boolean awaitJoinEstimationReady(EvaluationStatistics statistics) throws InterruptedException {
		long now = System.currentTimeMillis();
		long deadline = System.currentTimeMillis() + TimeUnit.SECONDS.toMillis(10);
		while (System.currentTimeMillis() < deadline) {
			if (statistics.supportsJoinEstimation()) {
				return true;
			}
			Thread.sleep(100);
		}
		deadline = System.currentTimeMillis() + TimeUnit.SECONDS.toMillis(50);
		while (System.currentTimeMillis() < deadline) {
			if (statistics.supportsJoinEstimation()) {
				return true;
			}
			System.out.println("Waiting for join estimation to become available, waited "
					+ (System.currentTimeMillis() - now) / 1000 + " seconds...");
			Thread.sleep(1000);
		}
		return statistics.supportsJoinEstimation();
	}

	private static Join asJoinNode(JoinScenario scenario) {
		StatementPattern left = new StatementPattern(
				Var.of("s"),
				Var.of("leftPredicate", scenario.left.predicate()),
				Var.of("leftObject", scenario.left.object()),
				Var.of("leftContext", THEME_GRAPH));

		StatementPattern right = new StatementPattern(
				Var.of("s"),
				Var.of("rightPredicate", scenario.right.predicate()),
				Var.of("rightObject", scenario.right.object()),
				Var.of("rightContext", THEME_GRAPH));

		return new Join(left, right);
	}

	private static void loadAllThemesInSingleGraph(SailRepository repository) {
		try (var connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			var inserter = new RDFInserter(connection);
			inserter.enforceContext(THEME_GRAPH);
			for (var themeDataset : ThemeDataSetGenerator.Theme.values()) {
				StopWatch started = StopWatch.createStarted();
				System.out.println("Loading theme dataset: " + themeDataset);
				ThemeDataSetGenerator.generate(themeDataset, inserter);
				System.out.println("Finished loading theme dataset: " + themeDataset + " in " + started);
			}
			connection.commit();
		}
	}

	private static List<JoinScenario> selectJoinScenarios(SailRepository repository) {
		Map<PoKey, Integer> pairCounts = new HashMap<>();

		try (SailRepositoryConnection connection = repository.getConnection();
				CloseableIteration<? extends Statement> statements = connection.getStatements(
						null, null, null, false, THEME_GRAPH)) {
			while (statements.hasNext()) {
				Statement statement = statements.next();
				PoKey key = PoKey.of(statement);
				pairCounts.merge(key, 1, Integer::sum);
			}
		}

		List<PoKey> topPairs = pairCounts.entrySet()
				.stream()
				.sorted(Map.Entry.comparingByValue(Comparator.reverseOrder()))
				.limit(TOP_PO_PAIRS)
				.map(Map.Entry::getKey)
				.collect(Collectors.toList());

		Map<PoKey, Set<Resource>> subjectsByPair = new HashMap<>();
		for (PoKey pair : topPairs) {
			subjectsByPair.put(pair, new HashSet<>());
		}

		try (SailRepositoryConnection connection = repository.getConnection();
				CloseableIteration<? extends Statement> statements = connection.getStatements(
						null, null, null, false, THEME_GRAPH)) {
			while (statements.hasNext()) {
				Statement statement = statements.next();
				PoKey key = PoKey.of(statement);
				Set<Resource> subjects = subjectsByPair.get(key);
				if (subjects != null) {
					subjects.add(statement.getSubject());
				}
			}
		}

		List<JoinScenario> candidates = new ArrayList<>();
		for (int i = 0; i < topPairs.size(); i++) {
			PoKey left = topPairs.get(i);
			Set<Resource> leftSubjects = subjectsByPair.get(left);
			if (leftSubjects == null || leftSubjects.isEmpty()) {
				continue;
			}

			for (int j = i + 1; j < topPairs.size(); j++) {
				PoKey right = topPairs.get(j);
				Set<Resource> rightSubjects = subjectsByPair.get(right);
				if (rightSubjects == null || rightSubjects.isEmpty()) {
					continue;
				}

				long intersection = intersectCount(leftSubjects, rightSubjects);
				if (intersection > 0L) {
					candidates.add(
							new JoinScenario(left, right, leftSubjects.size(), rightSubjects.size(), intersection));
				}
			}
		}

		candidates.sort(Comparator.comparingLong(JoinScenario::actualJoinCount).reversed());
		List<JoinScenario> strongCandidates = candidates.stream()
				.filter(candidate -> candidate.actualJoinCount() >= MIN_INTERSECTION)
				.collect(Collectors.toList());
		return strongCandidates.size() >= REQUIRED_JOIN_SCENARIOS ? strongCandidates : candidates;
	}

	private static long intersectCount(Set<Resource> first, Set<Resource> second) {
		Set<Resource> smaller = first.size() <= second.size() ? first : second;
		Set<Resource> larger = first.size() <= second.size() ? second : first;

		long count = 0L;
		for (Resource value : smaller) {
			if (larger.contains(value)) {
				count++;
			}
		}
		return count;
	}

	private record PoKey(IRI predicate, Value object) {

		private PoKey {
			Objects.requireNonNull(predicate, "predicate");
			Objects.requireNonNull(object, "object");
		}

		private static PoKey of(Statement statement) {
			return new PoKey(statement.getPredicate(), statement.getObject());
		}
	}

	private record JoinScenario(PoKey left, PoKey right, int leftSubjects, int rightSubjects, long actualJoinCount) {
	}
}
